const site = $('DB: Site').first().json;
const top = $('DB: Top30').all();
const peaks = $('DB: Peaks').all();
const ym = $('DB: YM Orders').all();
const ymGeo = $('DB: YM Geo').all();

const dt = new Date();
const msk = new Date(dt.getTime() + 3 * 3600000);
const dateStr = msk.toLocaleDateString('ru-RU', {day:'numeric', month:'long', year:'numeric'});

// Site section
let msg = `📊 Отчёт за ${dateStr}\n`;
msg += `━━━━━━━━━━━━━━━━━━━━\n`;
msg += `▎Сайт — ${site.orders_count || 0} заказов, ${site.gmv_eur || 0} EUR\n`;

if (top.length > 0) {
  msg += `Топ по выручке:\n`;
  top.slice(0, 10).forEach(r => {
    const p = r.json;
    msg += `• ${p.product} — ${p.revenue_eur} EUR (${p.qty} шт)\n`;
  });
  if (top.length > 10) {
    msg += `... и ещё ${top.length - 10} позиций\n`;
  }
}

// Payment methods
const card = site.gmv_card || 0;
const balance = site.gmv_balance || 0;
if (card > 0 || balance > 0) {
  msg += `\nОплата: картой ${card} EUR (${site.cnt_card || 0} шт), баланс ${balance} EUR (${site.cnt_balance || 0} шт)\n`;
}

// Peaks
if (peaks.length > 0) {
  const peakHours = peaks.slice(0,3).map(r => `${r.json.hour_msk}:00 (${r.json.orders} зак.)`).join(', ');
  msg += `Пики: ${peakHours}\n`;
}

// Cancelled
if (site.cancelled > 0) {
  msg += `Отменено: ${site.cancelled}\n`;
}

msg += `━━━━━━━━━━━━━━━━━━━━\n`;

// YM section
if (ym.length > 0) {
  const ymTotal = ym.reduce((s,r) => s + (r.json.amount_kopecks || 0), 0);
  const ymRub = Math.round(ymTotal / 100);
  const ymAvg = ym.length > 0 ? Math.round(ymRub / ym.length) : 0;

  msg += `▎Яндекс Маркет — ${ym.length} заказов, ${ymRub} ₽\n`;
  msg += `Крупные:\n`;
  ym.slice(0, 5).forEach(r => {
    const p = r.json;
    const rub = Math.round((p.amount_kopecks || 0) / 100);
    const city = p.city || p.region || '—';
    msg += `• ${rub} ₽ — ${city}\n`;
  });

  if (ymGeo.length > 0) {
    const geoStr = ymGeo.slice(0,4).map(r => `${r.json.region} (${r.json.orders} зак., ${r.json.total_rub} ₽)`).join(', ');
    msg += `Geography: ${geoStr}\n`;
  }

  msg += `Средний чек: ${ymAvg} ₽\n`;
  msg += `━━━━━━━━━━━━━━━━━━━━\n`;
}

// Total
const ymTotalRub = ym.reduce((s,r) => s + Math.round((r.json.amount_kopecks || 0) / 100), 0);
msg += `▎Итого: сайт ${site.gmv_eur || 0} EUR`;
if (ymTotalRub > 0) msg += ` + ЯМ ${ymTotalRub} ₽`;
msg += `\n`;

// Top leaders
if (top.length >= 2) {
  msg += `Лидеры: ${top[0].json.product} (${top[0].json.qty} шт), ${top[1].json.product} (${top[1].json.qty} шт)`;
}

return [{ json: { text: msg } }];
